def bo_dau(text: str) -> str:
    text = unicodedata.normalize("NFD", text)
    return "".join(c for c in text if unicodedata.category(c) != "Mn")

def tao_ma_hd(ten_hkd: str) -> str:
    return bo_dau(ten_hkd.upper()).replace(" ", "")

def filename_preview(so_hd: str, ten_hkd: str) -> str:
    if so_hd and ten_hkd:
        return f"HD_{so_hd}_{tao_ma_hd(ten_hkd)}.docx"
    return "HD_???.docx"

def replace_in_para(para, old: str, new: str):
    full = "".join(r.text for r in para.runs)
    if old not in full:
        return
    replaced = False
    for run in para.runs:
        if old in run.text:
            run.text = run.text.replace(old, new)
            replaced = True
            break
    if not replaced and para.runs:
        para.runs[0].text = full.replace(old, new)
        for run in para.runs[1:]:
            run.text = ""

def get_all_paras(doc):
    paras = list(doc.paragraphs)
    for table in doc.tables:
        for row in table.rows:
            for cell in row.cells:
                paras.extend(cell.paragraphs)
    return paras

def _xoa_ngay_ky(doc, ngay: str, thang: str, nam: str):
    TEMPLATE_DAY = "28"  # Ngày placeholder trong file template gốc
    ngay_str = ngay if ngay else "  "
    all_paras = get_all_paras(doc)
    for para in all_paras:
        full = "".join(r.text for r in para.runs)
        if (
            "lập vào ngày" in full
            or ("từ ngày" in full and TEMPLATE_DAY in full)
            or (
                "Ngày" in full and "tháng" in full and nam in full
                and "Luật" not in full and "Quốc Hội" not in full
            )
        ):
            for run in para.runs:
                if run.text == TEMPLATE_DAY:
                    run.text = ngay_str
            replace_in_para(para, f"lập vào ngày {TEMPLATE_DAY}", f"lập vào ngày {ngay_str}")
            replace_in_para(para, f"{TEMPLATE_DAY}/05/",           f"{ngay_str}/{thang}/")
            replace_in_para(para, f"Ngày {TEMPLATE_DAY} tháng",    f"Ngày {ngay_str} tháng")

# ─────────────────────────────────────────────
# ĐỌC SỐ TIỀN BẰNG CHỮ TIẾNG VIỆT
# ─────────────────────────────────────────────
def so_tien_bang_chu(so: int) -> str:
    """Chuyển số nguyên → chuỗi tiền Việt Nam (đồng)."""
    if so == 0:
        return "Không đồng"
    don_vi = ["", "nghìn", "triệu", "tỷ"]
    doc = ["không", "một", "hai", "ba", "bốn", "năm", "sáu", "bảy", "tám", "chín"]

    def doc_3so(n: int, is_first: bool = False) -> str:
        tram = n // 100
        chuc = (n % 100) // 10
        dv   = n % 10
        s = ""
        if tram:
            s += doc[tram] + " trăm"
        if chuc == 0 and dv == 0:
            return s
        if tram and chuc == 0:
            s += " linh"
        elif tram or not is_first:
            s += " " + (doc[chuc] + " mươi" if chuc != 1 else "mười")
        else:
            s += doc[chuc] + (" mươi" if chuc > 1 else " mười" if chuc == 1 else "")
        if dv:
            if chuc == 0 and not tram and is_first:
                s += " " + doc[dv]
            elif dv == 5 and chuc:
                s += " lăm"
            elif dv == 1 and chuc and chuc != 0:
                s += " mốt"
            else:
                s += " " + doc[dv]
        return s.strip()

    chunks, i = [], 0
    while so > 0:
        chunks.append((so % 1000, i))
        so //= 1000
        i += 1

    parts = []
    for idx, (chunk, power) in enumerate(reversed(chunks)):
        if chunk == 0:
            continue
        is_first = (idx == len(chunks) - 1)
        part = doc_3so(chunk, is_first)
        if don_vi[power]:
            part += " " + don_vi[power]
        parts.append(part)

    result = " ".join(parts).strip()
    # Chuẩn hóa
    result = result[0].upper() + result[1:] if result else ""
    return result + " đồng chẵn"


# ─────────────────────────────────────────────
# CẬP NHẬT BẢNG ĐIỀU 6 TRONG DOCX
# ─────────────────────────────────────────────
WNS = "{http://schemas.openxmlformats.org/wordprocessingml/2006/main}"

def _clear_and_set_tc(tc, text: str, center: bool = True):
    """Xóa nội dung <w:tc> rồi ghi text mới, giữ nguyên rPr (Times New Roman)."""
    import copy
    from lxml import etree

    # Lấy rPr của run đầu tiên để copy sang
    rpr = None
    for r in tc.findall(f".//{WNS}r"):
        rpr_el = r.find(f"{WNS}rPr")
        if rpr_el is not None:
            rpr = copy.deepcopy(rpr_el)
        break

    # Nếu không có rPr thì tạo mặc định Times New Roman
    if rpr is None:
        rpr = etree.Element(f"{WNS}rPr")
        rFonts = etree.SubElement(rpr, f"{WNS}rFonts")
        rFonts.set(f"{WNS}ascii", "Times New Roman")
        rFonts.set(f"{WNS}eastAsia", "Times New Roman")
        rFonts.set(f"{WNS}hAnsi", "Times New Roman")
        rFonts.set(f"{WNS}cs", "Times New Roman")

    # Xóa toàn bộ <w:r> trong tất cả <w:p>
    for p in tc.findall(f"{WNS}p"):
        for r in p.findall(f"{WNS}r"):
            p.remove(r)

    # Ghi text vào paragraph đầu tiên
    p = tc.find(f"{WNS}p")
    if p is None:
        return

    # Xử lý alignment trong pPr
    ppr = p.find(f"{WNS}pPr")
    if center:
        if ppr is None:
            ppr = etree.Element(f"{WNS}pPr")
            p.insert(0, ppr)
        jc = ppr.find(f"{WNS}jc")
        if jc is None:
            jc = etree.SubElement(ppr, f"{WNS}jc")
        jc.set(f"{WNS}val", "center")
    else:
        # Set jc=left rõ ràng (không thể xóa vì table style override)
        if ppr is None:
            ppr = etree.Element(f"{WNS}pPr")
            p.insert(0, ppr)
        jc = ppr.find(f"{WNS}jc")
        if jc is None:
            jc = etree.SubElement(ppr, f"{WNS}jc")
        jc.set(f"{WNS}val", "left")

    r_new = etree.SubElement(p, f"{WNS}r")
    r_new.insert(0, copy.deepcopy(rpr))
    t_new = etree.SubElement(r_new, f"{WNS}t")
    t_new.text = text
    if text and (text[0] == " " or text[-1] == " "):
        t_new.set("{http://www.w3.org/XML/1998/namespace}space", "preserve")


def dieu_6_update_table(doc, goi_cuocs: list):
    """Cập nhật bảng Điều 6 (Table index 1) với dữ liệu gói cước."""
    table = doc.tables[1]  # Bảng Điều 6 luôn là table index 1

    # Hàng data bắt đầu từ row index 2 (0=header, 1=label row (1)(2)...)
    DATA_ROW_START = 2
    # Row 5 = tổng, Row 6 = bằng chữ
    ROW_TOTAL   = 5
    ROW_BANGCHU = 6

    # Số hàng data available (row 2, 3, 4 = 3 hàng)
    data_rows = [table.rows[i] for i in range(DATA_ROW_START, ROW_TOTAL)]

    # Tính tổng
    tong = 0
    for g in goi_cuocs:
        try:
            tong += int(str(g.get("so_luong","0") or "0").replace(".","").replace(",","")) *                     int(str(g.get("gia_goi","0") or "0").replace(".","").replace(",",""))
        except:
            pass

    # Điền từng hàng data
    for idx, row in enumerate(data_rows):
        # Lấy các <w:tc> thực (không phải virtual merged)
        tcs = row._tr.findall(f"{WNS}tc")
        if idx < len(goi_cuocs):
            g = goi_cuocs[idx]
            try:
                sl  = int(str(g.get("so_luong","0") or "0").replace(".","").replace(",",""))
                gia = int(str(g.get("gia_goi","0") or "0").replace(".","").replace(",",""))
                tt  = sl * gia
            except:
                sl, gia, tt = 0, 0, 0

            vals = [
                str(idx + 1),
                g.get("ten_goi", ""),
                g.get("don_vi", "Gói"),
                str(sl) if sl else "",
                f"{gia:,}".replace(",", ".") if gia else "",
                f"{tt:,}".replace(",", ".") if tt else "",
                g.get("so_hd_trong_goi", ""),
            ]
            for ci, tc in enumerate(tcs):
                if ci < len(vals):
                    # Col 1 (Gói cước) canh trái, các cột khác canh giữa
                    _clear_and_set_tc(tc, vals[ci], center=(ci != 1))
        else:
            # Hàng dư → xóa sạch
            for tc in tcs:
                _clear_and_set_tc(tc, "", center=False)

    # Cập nhật tổng (row 5, real tc index 1) — giữ jc=both từ template
    row_total = table.rows[ROW_TOTAL]
    tcs_total = row_total._tr.findall(f"{WNS}tc")
    tong_str = f"{tong:,}".replace(",", ".") + " Đ"
    if len(tcs_total) >= 2:
        _clear_and_set_tc(tcs_total[1], tong_str, center=False)

    # Cập nhật bằng chữ (row 6, real tc index 0 — full width merge)
    row_bangchu = table.rows[ROW_BANGCHU]
    tcs_bangchu = row_bangchu._tr.findall(f"{WNS}tc")
    bang_chu = so_tien_bang_chu(tong)
    if tcs_bangchu:
        _clear_and_set_tc(tcs_bangchu[0], f"Bằng chữ: {bang_chu}", center=False)


# ─────────────────────────────────────────────
# DOCX → HTML PREVIEW
# ─────────────────────────────────────────────
def docx_to_html(doc_bytes: bytes) -> str:
    """Convert docx bytes → HTML giữ đúng format Word."""
    from lxml import etree as _et
    doc = Document(io.BytesIO(doc_bytes))
    WNS2 = "{http://schemas.openxmlformats.org/wordprocessingml/2006/main}"

    CSS = """
    <style>
    *{box-sizing:border-box;margin:0;padding:0}
    body{background:#f5f5f5}
    .page{
        font-family:'Times New Roman',serif;font-size:13pt;line-height:1.55;
        color:#111;background:white;
        padding:72px 80px;width:794px;margin:0 auto;
        box-shadow:0 1px 8px rgba(0,0,0,0.12);
    }
    p{margin:1px 0;min-height:1.2em}
    .tc{text-align:center}.tr{text-align:right}
    .tj{text-align:justify}.tl{text-align:left}
    .b{font-weight:bold}.i{font-style:italic}
    .ul{text-decoration:underline}
    table{width:100%;border-collapse:collapse;margin:4px 0}
    td{border:1px solid #333;padding:4px 8px;vertical-align:middle;font-size:12pt}
    .no-border td{border:none}
    </style>
    """

    def run_html(r_el):
        t = r_el.find(f"{WNS2}t")
        if t is None or not (t.text or ""): return ""
        txt = (t.text or "").replace("&","&amp;").replace("<","&lt;").replace(">","&gt;").replace("	","    ")
        rpr = r_el.find(f"{WNS2}rPr")
        b  = rpr is not None and rpr.find(f"{WNS2}b")  is not None
        it = rpr is not None and rpr.find(f"{WNS2}i")  is not None
        ul = rpr is not None and rpr.find(f"{WNS2}u")  is not None
        cls = " ".join(c for c,v in [("b",b),("i",it),("ul",ul)] if v)
        return f'<span class="{cls}">{txt}</span>' if cls else txt

    def para_html(p_el, no_space=False):
        ppr = p_el.find(f"{WNS2}pPr")
        jc_el = ppr.find(f"{WNS2}jc") if ppr is not None else None
        jcv = jc_el.get(f"{WNS2}val") if jc_el is not None else ""
        align = {"center":"tc","right":"tr","both":"tj","left":"tl"}.get(jcv,"")
        # Spacing before/after
        spacing = ppr.find(f"{WNS2}spacing") if ppr is not None else None
        mb = "0"
        if spacing is not None:
            after = spacing.get(f"{WNS2}after","")
            if after and after != "0": mb = f"{int(after)//20}pt"
        runs = "".join(run_html(r) for r in p_el.findall(f".//{WNS2}r"))
        style = f'margin-bottom:{mb}' if mb != "0" else ""
        sattr = f' style="{style}"' if style else ""
        return f'<p class="{align}"{sattr}>{runs if runs.strip() else "&nbsp;"}</p>'

    def table_html(tbl_el):
        # Kiểm tra có phải bảng quốc hiệu không (1 cột, 2 hàng đầu)
        rows = tbl_el.findall(f"{WNS2}tr")
        all_tcs = [tc for tr in rows for tc in tr.findall(f"{WNS2}tc")]
        is_header_table = len(rows) <= 2 and len(all_tcs) <= 2
        no_border_cls = " no-border" if is_header_table else ""

        html = [f'<table class="{no_border_cls.strip()}">']
        for tr in rows:
            html.append("<tr>")
            tcs = tr.findall(f"{WNS2}tc")
            for tc in tcs:
                tcPr = tc.find(f"{WNS2}tcPr")
                gs = tcPr.find(f"{WNS2}gridSpan") if tcPr is not None else None
                colspan = int(gs.get(f"{WNS2}val",1)) if gs is not None else 1
                vMerge = tcPr.find(f"{WNS2}vMerge") if tcPr is not None else None
                if vMerge is not None and vMerge.get(f"{WNS2}val","") != "restart":
                    continue
                cs_attr = f' colspan="{colspan}"' if colspan > 1 else ""
                cell_content = "".join(para_html(p) for p in tc.findall(f"{WNS2}p"))
                html.append(f"<td{cs_attr}>{cell_content}</td>")
            html.append("</tr>")
        html.append("</table>")
        return "\n".join(html)

    body = doc.element.body
    parts = [CSS, '<div class="page">']
    for child in body:
        tag = child.tag.split("}")[-1] if "}" in child.tag else child.tag
        if tag == "p":
            parts.append(para_html(child))
        elif tag == "tbl":
            parts.append(table_html(child))
        elif tag == "sdt":
            # Content control — render inner content
            sdtContent = child.find(f".//{WNS2}sdtContent")
            if sdtContent is not None:
                for sub in sdtContent:
                    stag = sub.tag.split("}")[-1] if "}" in sub.tag else sub.tag
                    if stag == "p": parts.append(para_html(sub))
                    elif stag == "tbl": parts.append(table_html(sub))
    parts.append("</div>")
    return "\n".join(parts)



def tao_mot_hop_dong(kh: dict, template_bytes: bytes) -> bytes:
    doc = Document(io.BytesIO(template_bytes))
    email_kh = kh.get("email_kh", "")
    ep = email_kh.split("@")[0] if "@" in email_kh else email_kh
    es = ("@" + email_kh.split("@")[1]) if "@" in email_kh else ""
    ten_hkd    = kh.get("ten_hkd", "")
    ten_hkd_ng = ten_hkd[4:].strip() if ten_hkd.upper().startswith("HKD ") else ten_hkd
    ma_hd      = tao_ma_hd(ten_hkd)
    tru_so     = kh.get("tru_so", "")
    dia_chi_gd = kh.get("dia_chi_gd", "") or tru_so
    ngay       = kh.get("ngay_ky", "")
    thang      = kh.get("thang_ky", "")
    nam        = kh.get("nam_ky", "2026")

    replacements = [
        ("EMAIL_KH_PLACEHOLDER",                          ep),
        ("@GMAIL.COM",                                    es),
        ("101",                                           kh.get("so_hd", "")),
        ("HKDKIMKIEN",                                    ma_hd),
        ("NHÀ NGHỈ KIM LIÊN",                            ten_hkd_ng),
        ("142/2 Phan Châu Trinh P.Hải Châu, Tp Đà Nẵng", tru_so),
        ("0904725978",                                    kh.get("dien_thoai", "")),
        ("049189011144",                                  kh.get("ma_so_thue", "")),
        ("PHẠM THỊ KIM LIÊN",                            kh.get("dai_dien", "")),
        ("Chủ HKD",                                       kh.get("chuc_vu", "")),
        ("Trương Thị Mỹ Châu",                           kh.get("ten_nv_ben_b", "")),
        ("0901959799",                                    kh.get("sdt_ben_b", "")),
        ("cuong.danghuy.ctv@mobifone.vn",                 kh.get("email_ben_b", "")),
        ("2550/UQ-MBF",                                       "2565/UQ-MBF"),   # Cập nhật số GUQ
        ("tháng 05",                                      f"tháng {thang}"),
        ("năm 2026",                                      f"năm {nam}"),
        ("/2026",                                         f"/{nam}"),
    ]

    all_paras = get_all_paras(doc)
    for old, new in replacements:
        if old and new and old != new:
            for para in all_paras:
                replace_in_para(para, old, new)

    if dia_chi_gd != tru_so and tru_so:
        found = 0
        for para in get_all_paras(doc):
            if tru_so in "".join(r.text for r in para.runs):
                found += 1
                if found == 2:
                    replace_in_para(para, tru_so, dia_chi_gd)
                    break

    _xoa_ngay_ky(doc, ngay, thang, nam)

    # Cập nhật bảng Điều 6 nếu có dữ liệu gói cước
    goi_cuocs = kh.get("goi_cuocs", [])
    if goi_cuocs:
        dieu_6_update_table(doc, goi_cuocs)

    buf = io.BytesIO()
    doc.save(buf)
    return buf.getvalue()

def validate(kh: dict) -> list:
    req_map = {
        "so_hd":        "Số hợp đồng",
        "ten_hkd":      "Tên HKD",
        "tru_so":       "Trụ sở chính",
        "dien_thoai":   "Số điện thoại",
        "ma_so_thue":   "Mã số thuế",
        "dai_dien":     "Họ tên đại diện",
        "chuc_vu":      "Chức vụ",
        "email_kh":     "Email khách hàng",
        "thang_ky":     "Tháng ký",
        "nam_ky":       "Năm ký",
        "ten_nv_ben_b": "Tên nhân viên Bên B",
        "email_ben_b":  "Email nhân viên Bên B",
        "sdt_ben_b":    "SĐT nhân viên Bên B",
    }
    errors = []
    for k, label in req_map.items():
        if not kh.get(k, "").strip():
            errors.append(f"{label}")
    if kh.get("dien_thoai") and not re.match(r"^0\d{9}$", kh["dien_thoai"]):
        errors.append("SĐT KH phải 10 số, bắt đầu bằng 0")
    if kh.get("sdt_ben_b") and not re.match(r"^0\d{9}$", kh["sdt_ben_b"]):
        errors.append("SĐT nhân viên phải 10 số, bắt đầu bằng 0")
    if kh.get("email_kh") and "@" not in kh["email_kh"]:
        errors.append("Email KH không đúng định dạng")
    if kh.get("email_ben_b") and "@" not in kh["email_ben_b"]:
        errors.append("Email nhân viên không đúng định dạng")
    return errors

