# ── RENDER STEPPER ─────────────────────────────────────────────
def render_stepper(current_step: int, errors: list):
    labels = ["Chọn template", "Nhập thông tin", "Kiểm tra", "Xem trước", "Tạo hợp đồng"]
    cells  = []
    for idx in range(1, len(labels) + 1):
        label = labels[idx - 1]
        if idx < current_step:
            bg, fg, lbl_c, icon = "#22c55e", "#ffffff", "#16a34a", "&#10003;"
        elif idx == current_step:
            bg, fg, lbl_c, icon = "#0B2D4D", "#ffffff", "#0B2D4D", str(idx)
        else:
            bg, fg, lbl_c, icon = "#f1f5f9", "#94a3b8", "#94a3b8", str(idx)

        cell = (
            '<div style="text-align:center;flex:1;padding:8px 4px;">'
            '<div style="width:32px;height:32px;border-radius:50%;'
            'background:{bg};color:{fg};display:inline-flex;'
            'align-items:center;justify-content:center;'
            'font-size:0.78rem;font-weight:700;margin:0 auto 4px;">{icon}</div>'
            '<div style="font-size:0.62rem;font-weight:600;color:{lbl_c};">{label}</div>'
            '</div>'
        ).format(bg=bg, fg=fg, lbl_c=lbl_c, icon=icon, label=label)
        cells.append(cell)

    html = (
        '<div style="background:white;border-radius:12px;padding:12px 24px;'
        'margin-bottom:16px;box-shadow:0 1px 4px rgba(0,0,0,0.06);'
        'display:flex;align-items:center;">'
        + "".join(cells) +
        '</div>'
    )
    st.markdown(html, unsafe_allow_html=True)

